import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function TakeTest() {
  const { testId } = useParams();
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();
  const [test, setTest] = useState(null);
  const [answers, setAnswers] = useState({});

  useEffect(() => {
    async function fetchTest() {
      try {
        const response = await fetch(`http://localhost:3001/tests/${testId}`);
        if (!response.ok) throw new Error("Тест не найден");
        const data = await response.json();
        if (data.courseId !== user.courseId) {
          toast.error("У вас нет доступа к этому тесту!");
          navigate("/courses");
          return;
        }
        setTest(data);
        console.log("Данные теста:", data);
      } catch (error) {
        toast.error("Ошибка загрузки теста");
        navigate("/courses");
      }
    }
    fetchTest();
  }, [testId, user.courseId, navigate]);

  const handleAnswerChange = (questionId, answerIndex) => {
    setAnswers((prevAnswers) => ({
      ...prevAnswers,
      [questionId]: answerIndex,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!test || test.questions.some((q) => answers[q.id] === undefined)) {
      toast.error("Ответьте на все вопросы!");
      return;
    }
    // Логика отправки теста (оставлена без изменений)
  };

  if (!test) return <div className="container mt-5"><h2>Загрузка...</h2></div>;

  console.log("Текущие ответы при рендере:", answers);

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Тест: {test.title}</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            {test.questions.map((question, qIndex) => (
              <div key={question.id || qIndex} className="mb-4">
                <h5>{qIndex + 1}. {question.text}</h5>
                {question.options.map((option, oIndex) => (
                  <div key={`${question.id || qIndex}-${oIndex}`} className="form-check">
                    <input
                      className="form-check-input"
                      type="radio"
                      name={`question-${qIndex}-${testId}`}
                      id={`question-${qIndex}-option-${oIndex}-${testId}`}
                      value={oIndex}
                      checked={answers[question.id] === oIndex}
                      onChange={() => handleAnswerChange(question.id, oIndex)}
                      required
                    />
                    <label
                      className="form-check-label"
                      htmlFor={`question-${qIndex}-option-${oIndex}-${testId}`}
                    >
                      {option}
                    </label>
                  </div>
                ))}
              </div>
            ))}
            <button type="submit" className="btn btn-primary w-100">
              Отправить
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default TakeTest;
